using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Blog>(b =>
        {
            // Breaking change #1: Discriminator property renamed from "Discriminator" to "$type".
            // Preserve old name so existing documents are still queryable.
            b.HasDiscriminator<string>("Discriminator");

            // Breaking change #2: id property no longer contains the discriminator prefix.
            // Existing documents use "Blog|1" format — keep that convention.
            b.HasDiscriminatorInJsonId();

            // Breaking change #3: Key property is now mapped directly to JSON "id",
            // eliminating the shadow __id property. Restore it so existing documents
            // that store the key under a separate JSON property still round-trip.
            b.HasShadowId();
        });

        // Breaking change #4: HasIndex now throws — Cosmos indexes all properties by default.
        // Removed: modelBuilder.Entity<Blog>().HasIndex(b => b.Name);
    }
}
class Blog { public string Id { get; set; } public string Name { get; set; } }

